"use strict";

var MotionGenerator = require("./MotionGenerator");
var RelativeTimeClip = require("../../ifr-motion/base/RelativeTimeClip");

/**
 * Wraps a motion generator to enable varying its playback speed.
 * @param {MotionGenerator} generator - motion generator to wrap
 * @param {number} initialSpeed - initial speed
 * @constructor
 * @extends MotionGenerator
 */
var VariableSpeedMotionGenerator = function(generator, initialSpeed)
{
	MotionGenerator.call(this);

	/** @type {MotionGenerator} */
	this._generator = generator;
	/** @type {RelativeTimeClip} */
	this._clip = new RelativeTimeClip(0, generator.getDuration(), initialSpeed);

	//setup mask, currently all joints active for entire time
	/** @type {Object<string, number>} */
	this._mask = {};
	/** @type {Object<string, boolean>} */
	this._activeDOFs = {};

	var dofNames = generator.getDOFs();
	var duration = this._clip.getDuration();
	for (var i = 0; i < dofNames.length; i++)
	{
		this._mask[dofNames[i]] = duration;
		this._activeDOFs[dofNames[i]] = true;
	}

	/** @type {Time} */
	this._latestUpdateTime = generator.getStartTime();
	/** @type {Time} */
	this._latestSpeedChangeTime = generator.getStartTime();
	/** @type {number} */
	this._sourceTimeAtLatestUpdate = 0;
};

VariableSpeedMotionGenerator.prototype = Object.create(MotionGenerator.prototype);
VariableSpeedMotionGenerator.prototype.constructor = VariableSpeedMotionGenerator;


/**
 * @returns {number}
 */
VariableSpeedMotionGenerator.prototype.getSpeed = function()
{
	return this._clip.getSpeed();
};

/**
 * @param {number} newSpeed - new speed
 */
VariableSpeedMotionGenerator.prototype.setSpeed = function(newSpeed)
{
	this._clip = new RelativeTimeClip(this._sourceTimeAtLatestUpdate, this._clip.getOutPoint(), newSpeed);
	this._latestSpeedChangeTime = this._latestUpdateTime;

	var elapsedTime = this._latestUpdateTime.subtract(this.getStartTime());
	var duration = elapsedTime + this._clip.getDuration();

	var maskKeys = Object.keys(this._mask);
	for (var mki = 0; mki < maskKeys.length; mki++)
	{
		var maskKey = maskKeys[mki];
		if (this._activeDOFs[maskKey])
		{
			this._mask[maskKey] = duration;
		}
	}
};

/**
 * @returns {string}
 * @override
 */
VariableSpeedMotionGenerator.prototype.getName = function()
{
	return this._generator.getName();
};

/**
 * @returns {Time}
 * @override
 */
VariableSpeedMotionGenerator.prototype.getStartTime = function()
{
	return this._generator.getStartTime();
};

/**
 * @returns {Time}
 * @override
 */
VariableSpeedMotionGenerator.prototype.getEndTime = function()
{
	return this.getStartTime().add(this.getDuration());
};

/**
 * @returns {number}
 * @override
 */
VariableSpeedMotionGenerator.prototype.getDuration = function()
{
	var longestDuration = 0;
	var maskKeys = Object.keys(this._mask);
	for (var mki = 0; mki < maskKeys.length; mki++)
	{
		var maskKey = maskKeys[mki];
		if (this._mask[maskKey] > longestDuration)
		{
			longestDuration = this._mask[maskKey];
		}
	}
	return longestDuration;
};

/**
 * @param {string} dofName
 * @returns {Time} returns end time for DOF or null if DOF fully not included
 * @override
 */
VariableSpeedMotionGenerator.prototype.getEndTimeForDOF = function(dofName)
{
	if (this._mask.hasOwnProperty(dofName))
	{
		return this.getStartTime().add(this._mask[dofName]);
	}
	else
	{
		return null;
	}
};

/**
 * @param {string} dofName
 * @returns {number} returns duration for DOF or null if DOF fully not included
 * @override
 */
VariableSpeedMotionGenerator.prototype.getDurationForDOF = function(dofName)
{
	if (this._mask.hasOwnProperty(dofName))
	{
		return this._mask[dofName];
	}
	else
	{
		return null;
	}
};

/**
 * Force this motion to end all its tracks at or before cropTime.  If a track
 * already ends before cropTime it is unchanged.  If a a track starts after
 * cropTime it is completely removed.
 *
 * @param {Time} cropTime - crop to end at this time if necessary
 * @param {string[]} [cropMask] - only crop dofs present in this mask (all dofs if omitted)
 * @override
 */
VariableSpeedMotionGenerator.prototype.cropEnd = function(cropTime, cropMask)
{
	var cropMaskKeys;
	if (cropMask != null) //null or undefined (eqnull)
	{
		cropMaskKeys = cropMask;
	}
	else
	{
		cropMaskKeys = Object.keys(this._mask);
	}

	var croppedDuration = cropTime.subtract(this.getStartTime());
	var cmi;
	if (croppedDuration > 0)
	{
		for (cmi = 0; cmi < cropMaskKeys.length; cmi++)
		{
			var cropThisDOF = cropMaskKeys[cmi];
			if (this._mask.hasOwnProperty(cropThisDOF))
			{
				if (this._mask[cropThisDOF] > croppedDuration)
				{
					this._mask[cropThisDOF] = croppedDuration;
					this._activeDOFs[cropThisDOF] = false;
				}
			}
		}
	}
	else
	{
		for (cmi = 0; cmi < cropMaskKeys.length; cmi++)
		{
			delete this._mask[cropMaskKeys[cmi]];
			this._activeDOFs[cropMaskKeys[cmi]] = false;
		}
	}

	// also crop underlying generator
	if (this.getStartTime().isGreater(cropTime))
	{
		this._generator.cropEnd(cropTime, cropMask);
	}
	else
	{
		var elapsedTime = cropTime.subtract(this._latestSpeedChangeTime);
		var sourceTime = this._clip.getSourceTime(elapsedTime);

		this._generator.cropEnd(this._generator.getStartTime().add(sourceTime), cropMask);
	}
};

/**
 * get all DOFs that are involved in this motion (except for any that
 * have been removed completely via cropping)
 *
 * @returns {string[]}
 * @override
 */
VariableSpeedMotionGenerator.prototype.getDOFs = function()
{
	return Object.keys(this._mask);
};

/**
 * @returns {boolean}
 * @override
 */
VariableSpeedMotionGenerator.prototype.hasEntered = function()
{
	return this._generator.hasEntered();
};

/**
 * @returns {boolean}
 * @override
 */
VariableSpeedMotionGenerator.prototype.hasExited = function()
{
	return this._generator.hasExited();
};

/**
 *
 * @param {Time} currentTime
 * @override
 */
VariableSpeedMotionGenerator.prototype.notifyUpdateStarted = function(currentTime)
{
	if (this.getStartTime().isGreater(currentTime))
	{
		this._generator.notifyUpdateStarted(currentTime);
	}
	else
	{
		var elapsedTime = currentTime.subtract(this._latestSpeedChangeTime);
		var sourceTime = this._clip.getSourceTime(elapsedTime);

		this._generator.notifyUpdateStarted(this._generator.getStartTime().add(sourceTime));

		this._latestUpdateTime = currentTime;
		this._sourceTimeAtLatestUpdate = sourceTime;
	}
};

/**
 *
 * @override
 */
VariableSpeedMotionGenerator.prototype.notifyUpdateFinished = function()
{
	this._generator.notifyUpdateFinished();
};

/**
 *
 * @override
 */
VariableSpeedMotionGenerator.prototype.notifyRemoved = function()
{
	this._generator.notifyRemoved();
};

/**
 * @param {string} dofName
 * @param {LayerState} partialRender
 * @param {Object} blackboard
 * @returns {number[]}
 * @override
 */
VariableSpeedMotionGenerator.prototype.getDOFState = function(dofName, partialRender, blackboard)
{
	return this._generator.getDOFState(dofName, partialRender, blackboard);
};


module.exports = VariableSpeedMotionGenerator;